external_knowledge:
- 'ocean' metaphorically represents a state;
- 'fish' represents the total population of a state;
- 'sizes of the lakes' metaphorically represents the total populations of the states, with the ocean with the most fish being the state with the highest population.

sql:
SELECT AVG(population_density) AS average_population_density
FROM counties
WHERE population_density = (SELECT MAX(population_density) FROM counties);

SELECT AVG(median_income) AS avg_median_income
FROM counties
WHERE median_income IS NOT NULL;

external_knowledge:
- "Brightest stars in the sky" metaphorically refers to counties with the highest number of access logs; 
- "Dazzling lights they emit" metaphorically refers to the number of access logs for each county; 
- "Median incomes" refer to the median income of each county;
- "Top ten in a descending order of their brightness" refers to ordering by the number of access logs in descending order and limiting the results to the top ten.

sql:
SELECT name
FROM counties
ORDER BY median_income DESC;

SELECT s.state_name
FROM states s
JOIN counties c ON s.statefp = c.statefp
WHERE c.median_income = (
    SELECT MAX(median_income) FROM counties
);
